claude-code.alternativeContent:
# Альтернатива: ручная настройка JSON
# ~/.config/claude/mcp.json
{
  "mcpServers": {
    "moira": {
      "type": "http",
      "url": "{{mcpUrl}}"
    }
  }
}

# Затем: /mcp → Authenticate

vscode.alternativeContent:
# Установите расширение MCP:
# ext install mcp-connector

# Затем в settings.json:
{
  "mcp.servers": {
    "moira": {
      "url": "{{mcpUrl}}",
      "transport": "http"
    }
  }
}

# Или: Command Palette → "MCP: Add Server"

zed.content:
# Zed editor:

# 1. Откройте Настройки (⌘+,)
# 2. Добавьте в settings.json в context_servers:
#
# "context_servers": {
#   "moira": {
#     "url": "{{mcpUrl}}"
#   }
# }
#
# 3. Перезапустите Zed
# 4. Авторизуйтесь

gemini-cli.content:
# Gemini CLI:

# 1. Отредактируйте ~/.gemini/settings.json:
#
# "mcpServers": {
#   "moira": {
#     "httpUrl": "{{mcpUrl}}"
#   }
# }
#
# 2. Выполните: gemini auth
# 3. Завершите OAuth авторизацию

connect.code:
# Claude Code (CLI)
claude mcp add moira https://{host}/mcp

# Cursor / VS Code (settings.json)
{
  "mcpServers": {
    "moira": {
      "url": "https://{host}/mcp"
    }
  }
}

execute.code:
# Moira возвращает:
{
  "directive": "Реализуйте функциональность
    согласно утверждённому плану",
  "completionCondition": "Все тесты проходят,
    код следует паттернам проекта",
  "inputSchema": { ... }
}

# Агент работает → отправляет результат
mcp__moira__step({
  processId: "abc-123",
  input: { ... }
})
